const items = $input.all().map(i => i.json);
const freqThreshold = parseFloat($env.FATIGUE_FREQ_THRESHOLD || 3.5);
const targetCpa = parseFloat($env.TARGET_CPA || 500);

// Top 5 spenders
const topSpend = [...items].sort((a, b) => b.spend - a.spend).slice(0, 5);

// Top 5 most efficient (lowest CPA with conversions)
const topEfficiency = items
  .filter(a => a.conversions > 0 && a.cpa)
  .sort((a, b) => a.cpa - b.cpa)
  .slice(0, 5);

// Fatigue candidates: high frequency AND CTR below average
const avgCtr = items.reduce((s, i) => s + (i.ctr || 0), 0) / (items.length || 1);
const fatigue = items.filter(a =>
  a.frequency > freqThreshold && (a.ctr || 0) < avgCtr
);

// Underperformers: spend > 0, CPA > target, 3+ days
const underperformers = items.filter(a =>
  a.spend > 0 && a.cpa && a.cpa > targetCpa
);

// Summary at adset level
const adsets = items.filter(i => i.entity_level === 'adset');
const totalSpend = adsets.reduce((s, i) => s + parseFloat(i.spend || 0), 0);
const totalConversions = adsets.reduce((s, i) => s + parseInt(i.conversions || 0), 0);
const avgCpa = totalConversions > 0 ? totalSpend / totalConversions : null;

// Build dynamic RAG query from actual fatigue candidates
const fatigueIds = fatigue.map(a => a.entity_id).slice(0, 5).join(', ');
const ragQuery = fatigueIds
  ? `performance data for adsets ${fatigueIds} frequency CTR trend declining`
  : 'ad sets with declining CTR and rising frequency last 7 days';

return [{
  json: {
    summary: { totalSpend, totalConversions, avgCpa, targetCpa },
    top_spend: topSpend,
    top_efficiency: topEfficiency,
    fatigue_candidates: fatigue,
    underperformers,
    rag_query: ragQuery
  }
}];

// Safely parse Gemini response — handles both string and pre-parsed object
const parse = (val) => {
  if (typeof val === 'string') {
    try { return JSON.parse(val); } catch(e) { return { error: 'parse_failed', raw: val }; }
  }
  return val;
};

const strategyRaw = $('Strategy Agent').item.json;
const strategyText = strategyRaw?.candidates?.[0]?.content?.parts?.[0]?.text;
const strategyData = parse(strategyText);

const optimisationRaw = $('Optimisation Agent').item.json;
const optimisationText = optimisationRaw?.candidates?.[0]?.content?.parts?.[0]?.text;
const optimisationData = parse(optimisationText);

return [{ json: { strategyData, optimisationData } }];

const parse = (val) => {
  if (typeof val === 'string') {
    try { return JSON.parse(val); } catch(e) { return { error: 'parse_failed', raw: val }; }
  }
  return val;
};

const strategyData = $json.strategyData;
const optimisationData = $json.optimisationData;

const copyRaw = $('Copywriting Agent').item.json?.candidates?.[0]?.content?.parts?.[0]?.text;
const copyData = parse(copyRaw);

const complianceRaw = $('Compliance Agent').item.json?.candidates?.[0]?.content?.parts?.[0]?.text;
const complianceData = parse(complianceRaw);

const date = new Date().toISOString().split('T')[0];

const report = {
  date,
  account_id: $env.META_AD_ACCOUNT_ID,
  strategy: strategyData,
  optimisation: optimisationData,
  copy_variants: copyData,
  compliance: complianceData,
  generated_at: new Date().toISOString()
};

const actionCount = optimisationData?.actions?.length || 0;
const confidence = Math.round((strategyData?.confidence || 0) * 100);
const topIssues = (strategyData?.top_issues || []).slice(0, 3).join(', ');

const slackText = [
  `*📊 Laiqa Daily Growth Report — ${date}*`,
  `*Strategy:* ${strategyData?.summary || 'N/A'}`,
  `*Top Issues:* ${topIssues || 'None'}`,
  `*Proposed Actions:* ${actionCount} queued`,
  `*Compliance:* ${complianceData?.overall_status || 'N/A'}`,
  `*Confidence:* ${confidence}%`
].join('\n');

return [{ json: { report, slackText, actions: optimisationData?.actions || [], compliance_verdict: complianceData?.overall_status || 'FAIL' } }];
